const body = $input.first().json.body || {};
const action = String(body.action || '').trim();
if (action === 'ping' || body.message === 'ping') return [{ json: { valid: 0, error: 'pong', action: 'ping' } }];
const ALLOWED = ['kb_list','kb_add_violation','kb_add_measure','kb_add_requirement','kb_add_norm','kb_delete'];
if (!ALLOWED.includes(action)) return [{ json: { valid: 0, error: 'Неизвестный action: ' + action } }];
const t = String(body.token || '').trim();
if (!/^[a-f0-9]{64}$/.test(t)) return [{ json: { valid: 0, error: 'Неверный формат токена' } }];
const s = (v, n) => String(v == null ? '' : v).slice(0, n);
const out = { valid: 1, action, token: t };
out.title = s(body.title, 500); out.category = s(body.category, 120); out.processes = s(body.processes, 1000);
out.description = s(body.description, 5000); out.criticality = ['low','medium','high','critical'].includes(body.criticality) ? body.criticality : 'medium';
out.mtype = ['organizational','technical','administrative','controlling'].includes(body.mtype) ? body.mtype : 'organizational';
out.name = s(body.name, 500); out.effect = s(body.effect, 2000); out.text = s(body.text, 20000);
out.norm_ref = s(body.norm_ref, 500); out.doc_name = s(body.doc_name, 500); out.doc_version = s(body.doc_version, 50); out.section = s(body.section, 200);
out.entity = ['violation','measure','requirement','norm'].includes(body.entity) ? body.entity : '';
out.id = parseInt(body.id, 10) || 0;
out.measure_ids = Array.isArray(body.measure_ids) ? body.measure_ids.map(x=>parseInt(x,10)).filter(Boolean) : [];
out.requirement_ids = Array.isArray(body.requirement_ids) ? body.requirement_ids.map(x=>parseInt(x,10)).filter(Boolean) : [];
out.risk_ids = Array.isArray(body.risk_ids) ? body.risk_ids.map(x=>parseInt(x,10)).filter(Boolean) : [];
return [{ json: out }];

const item = $input.first();
