async function embed(text){
  const EMBED_URL = 'http://130.100.94.119:8001/embed';
  try {
    const resp = await this.helpers.httpRequest({ method:'POST', url: EMBED_URL, headers:{'Content-Type':'application/json'}, body: JSON.stringify({ input: String(text).slice(0,2000), type:'passage' }), timeout: 8000, json: false });
    const j = (typeof resp==='string')?JSON.parse(resp):resp;
    if (j && Array.isArray(j.embedding) && j.embedding.length) return '[' + j.embedding.join(',') + ']';
  } catch(e) {}
  return null;
}
const src = $('Валидация').first().json;
const text = String(src.text || '').replace(/\r/g,'');
const words = text.split(/\s+/).filter(Boolean);
const CW = 400, OV = 40; const chunks = [];
if (!words.length) return [{ json: { _empty: true, doc_name: src.doc_name } }];
for (let i = 0; i < words.length; i += (CW - OV)) { chunks.push(words.slice(i, i + CW).join(' ')); if (i + CW >= words.length) break; }
const out = [];
for (let ci = 0; ci < chunks.length; ci++) {
  const vec = await embed(chunks[ci]);
  out.push({ json: { doc_name: src.doc_name || 'Документ', doc_version: src.doc_version || '', section: src.section || '', chunk_index: ci, chunk_text: chunks[ci], _vec: vec, _total: chunks.length } });
}
return out;
